bash_commands.command:
cd /workspace/kafka--0753c489

# Create a helper script to extract deprecated symbols
awk '
/@Deprecated/ {
    deprecated = 1
    next
}
deprecated && /public static final/ {
    # Extract the constant name
    if (match($0, /public static final [^ ]+ ([^ =;]+)/, arr)) {
        print arr[1]
    }
    deprecated = 0
}
' streams/src/main/java/org/apache/kafka/streams/StreamsConfig.java | head -30

